import{_ as a,o as s,c as t,a4 as o}from"./chunks/framework.CtnSHCpE.js";const u=JSON.parse('{"title":"Bash on z/OS","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/BashOnZOS.md","filePath":"Guides/BashOnZOS.md","lastUpdated":1776850763000}'),n={name:"Guides/BashOnZOS.md"};function i(r,e,l,h,p,d){return s(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="bash-on-z-os" tabindex="-1">Bash on z/OS <a class="header-anchor" href="#bash-on-z-os" aria-label="Permalink to &quot;Bash on z/OS&quot;">​</a></h1><p>Bash, short for &quot;Bourne-Again SHell,&quot; is a popular command-line interface and scripting language used primarily in Unix-based systems.</p><p>It is an alternative shell to the default Bourne shell (/bin/sh).</p><h2 id="why-bash-is-better" tabindex="-1">Why Bash is Better <a class="header-anchor" href="#why-bash-is-better" aria-label="Permalink to &quot;Why Bash is Better&quot;">​</a></h2><p>Here are some reasons why Bash is better:</p><ol><li><p>Tab completion: Bash supports tab completion, which means you can type the first few letters of a command or filename, and then press the Tab key to automatically complete it. This feature can help you save time and reduce typing errors.</p></li><li><p>Scripting: Bash is a powerful scripting language that allows you to automate complex tasks and perform operations that are not possible with the Bourne shell. Bash scripts can use variables, loops, conditions, and other programming constructs to perform a wide range of tasks.</p></li><li><p>Compatibility: Bash is compatible with the Bourne shell, which means that scripts written for the Bourne shell can run in Bash without modification. This makes it easy to migrate existing scripts to Bash without having to rewrite them.</p></li></ol><h2 id="how-to-set-bash-as-your-default-shell" tabindex="-1">How to Set Bash as Your Default Shell <a class="header-anchor" href="#how-to-set-bash-as-your-default-shell" aria-label="Permalink to &quot;How to Set Bash as Your Default Shell&quot;">​</a></h2><p>By default, z/OS uses the Bourne shell (/bin/sh) as the default shell for its z/OS UNIX and OMVS environment. However, Bash is a more powerful and feature-rich shell that offers several advantages over the Bourne shell.</p><p>To set Bash as your default shell on z/OS, follow these steps:</p><ol><li><p>Log in to your z/OS system and open a terminal session.</p></li><li><p>Enter the following command to check if Bash is installed:</p></li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>type bash</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If Bash is not installed, you can install it using the following command:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen install bash</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>For more details on how to use and setup zopen, see the <a href="/meta/Guides/ThePackageManager">zopen guide</a>.</p><p>Alternatively, you can download bash directly from <a href="https://github.com/zopencommunity/bashport/releases" target="_blank" rel="noreferrer">https://github.com/zopencommunity/bashport/releases</a>.</p><ol start="3"><li>Enter the following command to set Bash as your default shell in your OMVS segment:</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tsocmd &quot;ALTUSER USERID omvs(program(/path/to/bash))&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>where USERID is your z/OS user id and <code>/path/to/bash</code> is the path to your bash executable.</p><p>Please note that running this command requires elevated authority. For more information on authorization, please refer to the &#39;Authorization&#39; section of the following link: <a href="https://www.ibm.com/docs/en/zos/latest?topic=syntax-altuser-alter-user-profile" target="_blank" rel="noreferrer">https://www.ibm.com/docs/en/zos/latest?topic=syntax-altuser-alter-user-profile</a>. In case you do not have the necessary permissions, please consider requesting assistance from a system administrator to execute the command.</p><ol start="4"><li>To confirm that your OMVS Program Segment is set to bash, run the following command:</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tsocmd &quot;LISTUSER USERID OMVS&quot; | grep PROGRAM</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="5"><li>Log out of your z/OS system and log back in for the changes to take effect.</li></ol><p>Congratulations! You have now set Bash as your default shell on z/OS. You can now take advantage of its many features and capabilities to be more productive and efficient in your work.</p><h2 id="how-to-set-utf-8-encoding-in-bash" tabindex="-1">How to Set UTF-8 Encoding in Bash <a class="header-anchor" href="#how-to-set-utf-8-encoding-in-bash" aria-label="Permalink to &quot;How to Set UTF-8 Encoding in Bash&quot;">​</a></h2><p>To set UTF-8 encoding in Bash on z/OS, set the LANG environment variable.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export LANG=en_US.UTF-8</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Now try copying and pasting an emoji such as: ð</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>echo ð</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>You should see ð emitted to stdout.</p><p>Congratulations! You have now set UTF-8 encoding in Bash on z/OS. This can be beneficial if you need to work with Unicode characters in your scripts or commands.</p>',30)])])}const m=a(n,[["render",i]]);export{u as __pageData,m as default};
